@page "/"
@using ShipmentTracker.Client.Services
@using ShipmentTracker.Client.Models
@inject IShipmentService ShipmentService

<PageTitle>Home - ShipmentTracker</PageTitle>

<h1>Shipment Tracker</h1>
<p class="lead">Welcome to the logistics shipment tracking system.</p>

<div class="row mt-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track a Shipment</h5>
                <p class="card-text">Enter your tracking number to check the status and estimated delivery of your shipment.</p>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="Enter tracking number"
                           @bind="trackingNumber" @bind:event="oninput"
                           @onkeydown="HandleKeyDown" />
                    <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
                </div>
                @if (searchedShipment is not null)
                {
                    <div class="alert alert-success mt-3">
                        <strong>@searchedShipment.TrackingNumber</strong><br />
                        Status: <span class="badge bg-info">@searchedShipment.Status</span><br />
                        Destination: @searchedShipment.Destination<br />
                        @if (searchedShipment.EstimatedDelivery.HasValue)
                        {
                            <span>Estimated Delivery: @searchedShipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</span>
                        }
                    </div>
                }
                @if (trackError is not null)
                {
                    <div class="alert alert-warning mt-3">@trackError</div>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">For Dispatchers</h5>
                <p class="card-text">Manage all shipments, update statuses, and create new shipments.</p>
                <a href="/shipments" class="btn btn-outline-primary">Go to Dispatch Board</a>
            </div>
        </div>
    </div>
</div>

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? searchedShipment;
    private string? trackError;

    private async Task TrackShipment()
    {
        trackError = null;
        searchedShipment = null;

        if (string.IsNullOrWhiteSpace(trackingNumber))
        {
            trackError = "Please enter a tracking number.";
            return;
        }

        searchedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        if (searchedShipment is null)
        {
            trackError = "No shipment found with that tracking number.";
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Services
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Board - ShipmentTracker</PageTitle>

<h1>Dispatch Board</h1>
<p>Manage all shipments. Update statuses and create new shipments.</p>

<button class="btn btn-success mb-3" @onclick="() => showCreateForm = !showCreateForm">
    @(showCreateForm ? "Cancel" : "+ New Shipment")
</button>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Name" @bind="newShipment.CustomerName" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
            </div>
            <div class="row g-2 mt-2">
                <div class="col-md-3">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="estimatedDelivery" />
                </div>
                <div class="col-md-3 d-flex align-items-end">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input class="form-control" style="max-width: 300px;" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Customer</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.CustomerName</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString() ?? shipment.Status)">
                            <option value="Pending">Pending</option>
                            <option value="Picked Up">Picked Up</option>
                            <option value="In Transit">In Transit</option>
                            <option value="Out for Delivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Cancelled">Cancelled</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDelivery;
    private bool showCreateForm;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        string.IsNullOrWhiteSpace(filterText)
            ? shipments!
            : shipments!.Where(s => s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task CreateShipment()
    {
        newShipment.EstimatedDelivery = estimatedDelivery;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments!.Insert(0, created);
        newShipment = new();
        estimatedDelivery = null;
        showCreateForm = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-primary",
        "In Transit" => "bg-info",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Services
@using ShipmentTracker.Client.Models
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment - ShipmentTracker</PageTitle>

<h1>Track Your Shipment</h1>
<p>Enter your tracking number below to see real-time shipment status and estimated delivery.</p>

<div class="row">
    <div class="col-md-6">
        <div class="input-group mb-3">
            <input type="text" class="form-control" placeholder="e.g., SHP-20250101-ABC123"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (shipment is not null)
{
    <div class="card mt-3">
        <div class="card-header">
            <strong>Tracking: @shipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <span class="text-success fw-bold">@shipment.EstimatedDelivery.Value.ToString("dddd, MMMM dd, yyyy")</span>
                            }
                            else
                            {
                                <span class="text-muted">Not yet determined</span>
                            }
                        </dd>
                        <dt>Shipped On</dt>
                        <dd>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</dd>
                    </dl>
                </div>
            </div>

            <!-- Progress visualization -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         style="width: @GetProgressPercent(shipment.Status)%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}
else if (notFound)
{
    <div class="alert alert-warning mt-3">
        <strong>Not found.</strong> No shipment matches tracking number "<em>@searchedNumber</em>".
        Please double-check and try again.
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool notFound;
    private bool isLoading;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        notFound = false;
        shipment = null;
        searchedNumber = trackingNumber.Trim();

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        notFound = shipment is null;
        isLoading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "Picked Up" => "bg-primary",
        "In Transit" => "bg-info",
        "Out for Delivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Cancelled" => "bg-danger",
        "Delivered" => "bg-success",
        _ => "bg-info"
    };

    private static int GetProgressPercent(string status) => status switch
    {
        "Pending" => 10,
        "Picked Up" => 30,
        "In Transit" => 55,
        "Out for Delivery" => 80,
        "Delivered" => 100,
        "Cancelled" => 100,
        _ => 0
    };
}

