using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await db.Database.MigrateAsync();

        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        string[] roles = ["Dispatcher", "Customer"];

        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
            {
                await roleManager.CreateAsync(new IdentityRole(role));
            }
        }

        // Seed sample shipments if none exist
        if (!await db.Shipments.AnyAsync())
        {
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "SHP-20250520-ABC001",
                    Status = "In Transit",
                    Origin = "New York, USA",
                    Destination = "London, UK",
                    CustomerName = "Alice Johnson",
                    CustomerEmail = "alice@example.com",
                    EstimatedDelivery = DateTime.UtcNow.AddDays(3),
                    CreatedAt = DateTime.UtcNow.AddDays(-2)
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20250519-DEF002",
                    Status = "Out for Delivery",
                    Origin = "Tokyo, Japan",
                    Destination = "Sydney, Australia",
                    CustomerName = "Bob Smith",
                    CustomerEmail = "bob@example.com",
                    EstimatedDelivery = DateTime.UtcNow.AddDays(1),
                    CreatedAt = DateTime.UtcNow.AddDays(-5)
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20250518-GHI003",
                    Status = "Pending",
                    Origin = "Berlin, Germany",
                    Destination = "São Paulo, Brazil",
                    CustomerName = "Carlos Lima",
                    CustomerEmail = "carlos@example.com",
                    EstimatedDelivery = DateTime.UtcNow.AddDays(7),
                    CreatedAt = DateTime.UtcNow.AddDays(-1)
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20250515-JKL004",
                    Status = "Delivered",
                    Origin = "Shanghai, China",
                    Destination = "Los Angeles, USA",
                    CustomerName = "Diana Chen",
                    CustomerEmail = "diana@example.com",
